function cloneBaseTranslations() {
  return JSON.parse(JSON.stringify(TRANSLATIONS.es));
}

['en', 'ca', 'eu', 'gl', 'val', 'fr', 'de', 'zh'].forEach((languageCode) => {
  TRANSLATIONS[languageCode] = cloneBaseTranslations();
});

function applyLanguageOverrides(path, values) {
  Object.entries(values).forEach(([languageCode, value]) => {
    const segments = path.split('.');
    let target = TRANSLATIONS[languageCode];

    for (let index = 0; index < segments.length - 1; index += 1) {
      target = target[segments[index]];
    }

    target[segments[segments.length - 1]] = value;
  });
}

/**
 * Builds a readable fallback label from a translation key when English text is missing.
 * @param {string} key
 * @returns {string}
 */
function humanizeTranslationKey(key) {
  const leaf = String(key || '').split('.').pop() || '';
  const withSpaces = leaf.replace(/([a-z])([A-Z])/g, '$1 $2').replace(/_/g, ' ').trim();
  if (!withSpaces) {
    return 'Text';
  }
  return withSpaces.charAt(0).toUpperCase() + withSpaces.slice(1);
}

