/**
 * Heuristic check for likely Spanish content that should be hidden in strict English mode.
 * @param {string} value
 * @returns {boolean}
 */
function looksSpanish(value) {
  return /\b(el|la|los|las|de|del|para|con|sin|por|que|una|uno|más|solo|cocina|balanza|inteligente|libro|recetas|viaje|juguete|mascotas|belleza|hogar|deportes|accesorios|fotografia|música|musica|jardin|electrónica|electronica|portatil|portátil)\b|[áéíóúñ]/i.test(String(value || ''));
}

/**
 * Normalizes mojibake and accents to improve translation lookups.
 * @param {string} value
 * @returns {string}
 */
function normalizeTextForLookup(value) {
  return String(value || '')
    .replace(/Ã¡/g, 'a')
    .replace(/Ã©/g, 'e')
    .replace(/Ã­/g, 'i')
    .replace(/Ã³/g, 'o')
    .replace(/Ãº/g, 'u')
    .replace(/Ã±/g, 'n')
    .replace(/Â/g, '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .trim();
}

